import{_ as o,o as t,c as a,a2 as r}from"./chunks/framework.Crpw6aS5.js";const n=JSON.parse('{"title":"2020年 · 60年投资生涯的信念告白","description":"","frontmatter":{},"headers":[],"relativePath":"05_quotes/by-year/2020年.md","filePath":"05_quotes/by-year/2020年.md"}'),l={name:"05_quotes/by-year/2020年.md"};function u(q,e,c,p,h,s){return t(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="_2020年-·-60年投资生涯的信念告白" tabindex="-1">2020年 · 60年投资生涯的信念告白 <a class="header-anchor" href="#_2020年-·-60年投资生涯的信念告白" aria-label="Permalink to &quot;2020年 · 60年投资生涯的信念告白&quot;">​</a></h1><blockquote><p>&quot;不要做空美国。没有人能以做空祖国来致富。&quot;——巴菲特</p></blockquote><p>本页收录2020年<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>年报中的经典语录。这一年巴菲特90岁，执笔致股东信正好60年。这封信不仅是投资哲学的系统总结，更是他对美国资本主义最真挚的信念宣言。</p><hr><h2 id="核心金句" tabindex="-1">核心金句 <a class="header-anchor" href="#核心金句" aria-label="Permalink to &quot;核心金句&quot;">​</a></h2><blockquote><p>&quot;不要做空美国。没有人能以做空祖国来致富。在伯克希尔58年的历史中，我们最成功的投资决策都与对美国的信念有关。&quot;</p></blockquote><blockquote><p>&quot;查理和我希望伯克希尔拥有全部或部分具有良好经济特征和优秀管理层的多元业务组合。然而，我们是否控股这些企业并不重要。&quot;</p></blockquote><blockquote><p>&quot;拥有一家优秀企业的不控股股权，比经营一家边缘企业百分之百的股权更有利可图，也更有乐趣，且省心得多。&quot;</p></blockquote><blockquote><p>&quot;留存收益在美国企业的发展历程中始终发挥着推动力量。Carnegie和Rockefeller时代奏效的方法，多年以来同样为数百万股东带来了可观的回报。&quot;</p></blockquote><blockquote><p>&quot;我们的保险业务在伯克希尔53年来的核心地位从未改变。浮存金——这些虽不归我们所有但可自由支配的资金——是我们相对于所有竞争对手最核心的结构性优势。&quot;</p></blockquote><blockquote><p>&quot;我们在2008年金融危机最严峻时，写给《纽约时报》的文章里说：买入美国股票。这看起来是冒险，但查理和我知道，这是我们一生中最好的买入时机之一。&quot;</p></blockquote><blockquote><p>&quot;投资最重要的事情是理解留存收益如何被再投资。复利在发挥作用。&quot;</p></blockquote><blockquote><p>&quot;伯克希尔持有的苹果股票从5.2%增加到5.4%，这对我们毫无成本，原因是苹果公司持续回购其股票。我们通过简单的持有，分享了企业不断壮大的果实。&quot;</p></blockquote><hr><h2 id="本年背景" tabindex="-1">本年背景 <a class="header-anchor" href="#本年背景" aria-label="Permalink to &quot;本年背景&quot;">​</a></h2><p>2020年是巴菲特执笔致股东信60周年（1962-2020）。这封信回顾了伯克希尔1965年以来的投资历程：账面价值从19美元增长到146,186美元，年复合增长率19.4%；市值从1964年的2,810,526%增长，远超标普500的23,454%。</p><p>2020年，伯克希尔没有进行大规模收购，但通过大规模股票回购（247亿美元），提升了每股内在价值。同年，巴菲特向新冠疫情中的慈善机构捐赠显著增加，并将99%以上的个人财富承诺捐给慈善机构。</p><hr><h2 id="深入阅读" tabindex="-1">深入阅读 <a class="header-anchor" href="#深入阅读" aria-label="Permalink to &quot;深入阅读&quot;">​</a></h2><p><a href="/search.html?q=→ 原文翻译">01_letters/2020年/翻译</a> · <a href="/search.html?q=→ 核心总结">01_letters/2020年/核心总结</a> · <a href="/search.html?q=→ 思维导图">01_letters/2020年/思维导图</a></p>',20)])])}const b=o(l,[["render",u]]);export{n as __pageData,b as default};
